 using Payments;

 namespace PaymentGateway.Tests;

 [TestClass]
 public class ChargeTests
 {
     private Payments.PaymentGateway _gateway = null!;

     [TestInitialize]
     public void Setup() => _gateway = new Payments.PaymentGateway();

     // ── Happy-path ──────────────────────────────────────────────

     [TestMethod]
     public async Task ChargeAsync_ValidCard_ReturnsSuccess()
     {
         var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

         Assert.IsTrue(result.Success);
         Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
     }

     [TestMethod]
     public async Task ChargeAsync_ValidCard_ReturnsUniqueChargeId()
     {
         var r1 = await _gateway.ChargeAsync("tok_visa_1", 10m);
         var r2 = await _gateway.ChargeAsync("tok_visa_2", 20m);

         Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
     }

     // ── Boundary amounts ────────────────────────────────────────

     [TestMethod]
     public async Task ChargeAsync_MinimumAmount_Succeeds()
     {
         var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

         Assert.IsTrue(result.Success);
     }

     [TestMethod]
     public async Task ChargeAsync_LargeAmount_Succeeds()
     {
         var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

         Assert.IsTrue(result.Success);
     }

     // ── Invalid inputs ──────────────────────────────────────────

     [TestMethod]
     public async Task ChargeAsync_ZeroAmount_Fails()
     {
         var result = await _gateway.ChargeAsync("tok_valid", 0m);

         Assert.IsFalse(result.Success);
     }

     [TestMethod]
     public async Task ChargeAsync_NegativeAmount_Fails()
     {
         var result = await _gateway.ChargeAsync("tok_valid", -5m);

         Assert.IsFalse(result.Success);
     }

     [TestMethod]
     public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentNullException>(
             () => _gateway.ChargeAsync(null!, 10m));
     }

     [TestMethod]
     public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentException>(
             () => _gateway.ChargeAsync("", 10m));
     }

     [TestMethod]
     public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentException>(
             () => _gateway.ChargeAsync("   ", 10m));
     }
 }

 [TestClass]
 public class RefundTests
 {
     private Payments.PaymentGateway _gateway = null!;

     [TestInitialize]
     public void Setup() => _gateway = new Payments.PaymentGateway();

     // ── Happy-path ──────────────────────────────────────────────

     [TestMethod]
     public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
     {
         var result = await _gateway.RefundAsync("ch_abc123");

         Assert.IsTrue(result.Success);
         Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
     }

     [TestMethod]
     public async Task RefundAsync_ValidChargeId_ReturnsUniqueRefundId()
     {
         var r1 = await _gateway.RefundAsync("ch_one");
         var r2 = await _gateway.RefundAsync("ch_two");

         Assert.AreNotEqual(r1.RefundId, r2.RefundId);
     }

     // ── Invalid inputs ──────────────────────────────────────────

     [TestMethod]
     public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentNullException>(
             () => _gateway.RefundAsync(null!));
     }

     [TestMethod]
     public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentException>(
             () => _gateway.RefundAsync(""));
     }

     [TestMethod]
     public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
     {
         await Assert.ThrowsExactlyAsync<ArgumentException>(
             () => _gateway.RefundAsync("   "));
     }
 }

 [TestClass]
 public class ChargeAndRefundIntegrationTests
 {
     private Payments.PaymentGateway _gateway = null!;

     [TestInitialize]
     public void Setup() => _gateway = new Payments.PaymentGateway();

     [TestMethod]
     public async Task ChargeAndRefund_EndToEnd_BothSucceed()
     {
         var charge = await _gateway.ChargeAsync("tok_visa_e2e", 75.00m);
         Assert.IsTrue(charge.Success, "Charge should succeed");

         var refund = await _gateway.RefundAsync(charge.ChargeId);
         Assert.IsTrue(refund.Success, "Refund of a valid charge should succeed");
         Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
     }
 }

 [TestClass]
 public class RecordEqualityTests
 {
     [TestMethod]
     public void ChargeResult_EqualValues_AreEqual()
     {
         var a = new ChargeResult("ch_1", true);
         var b = new ChargeResult("ch_1", true);

         Assert.AreEqual(a, b);
     }

     [TestMethod]
     public void ChargeResult_DifferentValues_AreNotEqual()
     {
         var a = new ChargeResult("ch_1", true);
         var b = new ChargeResult("ch_2", true);

         Assert.AreNotEqual(a, b);
     }

     [TestMethod]
     public void RefundResult_EqualValues_AreEqual()
     {
         var a = new RefundResult("rf_1", true);
         var b = new RefundResult("rf_1", true);

         Assert.AreEqual(a, b);
     }

     [TestMethod]
     public void RefundResult_DifferentValues_AreNotEqual()
     {
         var a = new RefundResult("rf_1", true);
         var b = new RefundResult("rf_1", false);

         Assert.AreNotEqual(a, b);
     }
 }
